import { SourceFrequency } from '@domain/entry';
import { PublicActionPage } from '@domain/publicActionPage';
import {
  useGetIsFreeTickets,
  useTotalAmount,
} from '@pages/ActionPages/pages/PublicActionPage/ActionPageView/ActionPageLayout/ActionPageBody/hooks';
import { TurnstileChallenge } from '@pages/ActionPages/pages/PublicActionPage/ActionPageView/ActionPageLayout/ActionPageBody/TurnstileChallenge/TurnstileChallenge';
import { useFeatureFlag } from '@state/featureFlags/hooks/useFeatureFlag';
import { formatCurrency } from '@ui/utils';
import { getShadeColor } from '@ui/utils/getShadeColor';
import { isDonationPage } from '@utils/isDonationPage/isDonationPage';
import currency from 'currency.js';
import { useCallback, useMemo } from 'react';
import { useFormContext } from 'react-hook-form';
import { ExclamationCircleIcon } from 'src/builder/PublicActionPage/components/icons/ExclamationCircleIcon';
import { Label } from 'src/builder/PublicActionPage/components/Label';
import { Paragraph } from 'src/builder/PublicActionPage/components/Paragraph';
import { ActionPageSubmitButton } from '../../../../components/ActionPageSubmitButton';
import { FormSingleCheckboxControl } from '../../../../components/CheckboxControl/FormSingleCheckboxControl';
import { Meta } from '../../../../components/Meta';
import { PaymentMethodForm } from '../../../../components/PaymentMethodForm';
import { useContrastColor } from '../../../../utils/useContrastColor';
import { MAX_TICKET_QUANTITY, useEventSelectedTicketContext } from '../../../EventPageLayout/hooks';
import { PromoCodeInput } from '../components/PromoCodeInput/PromoCodeInput';
import { useTicketTotalAmount } from '../hooks';

type Props = {
  actionPage: PublicActionPage;
  caption?: React.ReactNode;
  form?: string;
  isEmbedded: boolean;
  isEvent: boolean;
  isLoading?: boolean;
  isPreview?: boolean;
  paddingTop?: string;
  showFrequencyOnSubmissionButton?: boolean;
  showPaymentBlock: boolean;
  showSubmissionButton?: boolean;
  totalFees: number;
};

export const ActionPagePaymentBlock = ({
  actionPage,
  caption,
  form = 'action-page-form',
  isEmbedded,
  isEvent,
  isLoading,
  isPreview = false,
  paddingTop = 'pt-8',
  showFrequencyOnSubmissionButton = true,
  showPaymentBlock,
  showSubmissionButton = true,
  totalFees,
}: Props) => {
  const enableBankDraft = useFeatureFlag('actionPages2.publicRender.enableBankDraft');
  const enablePlaidLink = useFeatureFlag('settings.usePlaidBankAccountVerification') && !isPreview;
  const { amountConfiguration } = actionPage;
  const enableMaxVerificationLimit = useFeatureFlag(
    'settings.useMaxVerificationLimit',
    { defaultValue: false },
    actionPage.account.id
  );
  const turnstileEnabled = actionPage.account.accountConfiguration.useTurnstile && !isPreview;

  const turnstileInteractiveEnabled =
    useFeatureFlag('actionPages.turnstileInteractive', false, actionPage.account.id) && !isPreview;

  const { formState, watch } = useFormContext();
  const promoCodeDiscount = watch('promoCodeDiscount') ?? 0;
  const type = watch('type');
  const hasValidDonorPaymentMethod = watch('hasValidDonorPaymentMethod');
  const customerCoveredFees =
    actionPage.pageType === 'storefront' ? true : watch('customerCoveredFees');
  const eventTicketsAttributes = watch('eventTicketsAttributes');
  const selectedFrequency: SourceFrequency | undefined = watch('frequency');
  const donationAmount = useTotalAmount();
  const ticketTotalAmount = useTicketTotalAmount(actionPage);
  const { totalTicketCount } = useEventSelectedTicketContext();
  const totalAmount = Math.max(
    donationAmount + ticketTotalAmount + (customerCoveredFees ? totalFees : 0) - promoCodeDiscount,
    0
  );
  const isFreeTickets = useGetIsFreeTickets(actionPage);
  const expressCheckoutMethod = watch('expressCheckoutMethod');
  const { designConfiguration, fieldConfiguration, pageType } = actionPage;

  const isInUpgradeChain = watch('isInUpgradeChain');
  const hasValidUpgradePaymentMethod = watch('hasValidUpgradePaymentMethod');
  const futurePledgeSelected = watch('futurePledgeSelected');
  const promoCodeAttributes = watch('promoCodeAttributes');
  const region = watch('addressAttributes.region');
  const { disallowedStates } = actionPage.account.accountConfiguration;
  const restrictedStateSelected = useMemo(() => {
    return !!region && disallowedStates?.split(',').includes(region);
  }, [disallowedStates, region]);

  const canSavePaymentMethod =
    ['credit_card', 'plaid_bank_account', 'bank_account', 'paypal'].includes(type) &&
    !!watch('donorProfile');

  // change ACH verification limit to $3000 if set in configuration of Yodlee / Plaid whitelist
  const achVerificationLimit = useMemo(
    () =>
      enableMaxVerificationLimit
        ? 1000001 * 100
        : actionPage?.account?.accountConfiguration?.increasedVerifiedLimit
          ? 3000 * 100
          : 200 * 100,
    [enableMaxVerificationLimit, actionPage?.account?.accountConfiguration?.increasedVerifiedLimit]
  );

  const transactionLimitError = useMemo(() => {
    if (
      !!amountConfiguration?.transactionMaximum &&
      donationAmount + ticketTotalAmount !== 0 &&
      donationAmount +
        ticketTotalAmount +
        (customerCoveredFees ? totalFees : 0) -
        promoCodeDiscount >
        amountConfiguration?.transactionMaximum
    ) {
      const maximumCurrencyValue = currency(amountConfiguration?.transactionMaximum / 100);

      const maximumAmount = formatCurrency(maximumCurrencyValue.intValue, {
        hideDecimal: maximumCurrencyValue.cents() === 0,
      });

      return `Maximum limit of ${maximumAmount}`;
    }

    if (
      !!amountConfiguration?.transactionMinimum &&
      donationAmount + ticketTotalAmount !== 0 &&
      donationAmount +
        ticketTotalAmount +
        (customerCoveredFees ? totalFees : 0) -
        promoCodeDiscount <
        amountConfiguration?.transactionMinimum
    ) {
      // Ignore transaction limit for free tickets
      if (
        donationAmount === 0 &&
        Math.max(
          ticketTotalAmount + (customerCoveredFees ? totalFees : 0) - promoCodeDiscount,
          0
        ) === 0
      ) {
        return undefined;
      }

      const minimumCurrencyValue = currency(amountConfiguration?.transactionMinimum / 100);

      const minimumAmount = formatCurrency(minimumCurrencyValue.intValue, {
        hideDecimal: minimumCurrencyValue.cents() === 0,
      });

      return `Minimum amount of ${minimumAmount} required.`;
    }

    return undefined;
  }, [
    amountConfiguration,
    customerCoveredFees,
    donationAmount,
    promoCodeDiscount,
    ticketTotalAmount,
    totalFees,
  ]);

  const submitForm = useCallback(() => {
    if (isPreview) {
      return;
    }

    (document.getElementById('action-page-form') as HTMLFormElement)?.requestSubmit();
  }, [isPreview]);

  const showSubmitButton = useMemo(() => {
    if (isFreeTickets) {
      return true;
    }

    return (
      (showSubmissionButton &&
        !expressCheckoutMethod &&
        ((type !== 'applepay' && (type !== 'paypal' || isInUpgradeChain)) ||
          hasValidDonorPaymentMethod)) ||
      (type === 'googlepay' && isInUpgradeChain)
    );
  }, [
    showSubmissionButton,
    expressCheckoutMethod,
    type,
    isFreeTickets,
    isInUpgradeChain,
    hasValidDonorPaymentMethod,
  ]);

  const isDisabled = !formState.isValid
    ? true
    : isEvent
      ? ((eventTicketsAttributes?.length ?? 0) === 0 &&
          donationAmount === 0 &&
          ticketTotalAmount === 0) ||
        (actionPage.event?.requireDonationForFreeTickets &&
          ticketTotalAmount === 0 &&
          !donationAmount) ||
        Object.keys(formState.errors).some((key) => key.includes('attendee')) ||
        totalTicketCount > MAX_TICKET_QUANTITY ||
        (promoCodeAttributes?.id && !eventTicketsAttributes.length) ||
        transactionLimitError
      : !donationAmount;

  const {
    businessDirectDebitEnabled,
    creditCardEnabled,
    paypalEnabled,
    personalDirectDebitEnabled,
  } = actionPage.paymentConfiguration || {};

  const { actionElementColorPrimary } = designConfiguration;
  const { actionElementText } = fieldConfiguration;
  const actionButtonTextColor = useContrastColor(
    actionElementColorPrimary === 'neutral.0' ? '#fff' : (actionElementColorPrimary ?? '#fff')
  );
  const actionButtonHoverBgColor = getShadeColor(actionElementColorPrimary, -20);

  return (
    <>
      {showPaymentBlock &&
      isDonationPage(pageType) &&
      (!isInUpgradeChain || !hasValidUpgradePaymentMethod) &&
      !expressCheckoutMethod &&
      (!hasValidDonorPaymentMethod || caption) ? (
        <div
          className="flex w-full flex-col justify-center pt-8"
          id="action-page-payment-block"
          key="payment-methods"
          style={{ paddingTop }}

