          style={{ paddingTop }}
        >
          {!hasValidDonorPaymentMethod ? caption : null}
          {!hasValidDonorPaymentMethod && totalAmount > 0 ? (
            <>
              <PaymentMethodForm
                achVerificationLimit={achVerificationLimit}
                allowedPaymentMethods={{
                  bankAccount:
                    (enableBankDraft &&
                      !enablePlaidLink &&
                      (businessDirectDebitEnabled || personalDirectDebitEnabled)) ??
                    false,
                  creditCard: !!creditCardEnabled,
                  enablePlaidBusinessACH: businessDirectDebitEnabled ?? undefined,
                  enablePlaidPersonalACH: personalDirectDebitEnabled ?? undefined,
                  paypal: !isEmbedded && !!paypalEnabled,
                  plaidBankAccount:
                    (enableBankDraft &&
                      enablePlaidLink &&
                      (businessDirectDebitEnabled || personalDirectDebitEnabled)) ??
                    false,
                }}
                cardZipRequired
                isPreview={isPreview}
                onSubmitExternal={submitForm}
                paymentLabel={actionPage.account.displayName}
                showBillingAddress={false}
                showCardholderName={false}
                showCardZip
                showCreditCardInformationTitle={false}
                totalAmount={totalAmount}
              />
              {canSavePaymentMethod ? (
                <>
                  <FormSingleCheckboxControl
                    formControlProps={{ className: 'mb-1 mt-4 text-p' }}
                    name="savePaymentMethod"
                  >
                    Store this payment method for future use.
                  </FormSingleCheckboxControl>
                  <Meta className="ml-6">
                    Anedot securely stores your payment method for your future use.
                  </Meta>
                </>
              ) : null}
            </>
          ) : null}
        </div>
      ) : null}
      {turnstileEnabled || turnstileInteractiveEnabled ? (
        <TurnstileChallenge appearance={turnstileInteractiveEnabled ? 'always' : undefined} />
      ) : null}
      <PromoCodeInput actionPage={actionPage} ticketTotalAmount={ticketTotalAmount} />
      {totalTicketCount > MAX_TICKET_QUANTITY && (
        <Paragraph className="-mb-2 mt-4 text-red-500">
          Limit of {MAX_TICKET_QUANTITY} tickets per transaction. Remove tickets to proceed.
        </Paragraph>
      )}
      {transactionLimitError && (
        <Paragraph className="-mb-2 mt-4 text-red-500">{transactionLimitError}</Paragraph>
      )}
      {showSubmitButton ? (
        <>
          <ActionPageSubmitButton
            actionButtonBgColor={actionElementColorPrimary}
            actionButtonHoverBgColor={actionButtonHoverBgColor}
            actionButtonText={actionElementText}
            actionButtonTextColor={actionButtonTextColor}
            customerCoveredFees={customerCoveredFees}
            donationAmount={donationAmount}
            form={isPreview ? undefined : form}
            futurePledgeDate={
              (futurePledgeSelected && actionPage.amountConfiguration?.futurePledgeDate) ||
              undefined
            }
            isDisabled={isDisabled}
            isLoading={isLoading}
            key="submit-button"
            selectedFrequency={selectedFrequency}
            showFrequency={showFrequencyOnSubmissionButton}
            totalAmount={totalAmount}
          />
          {!!eventTicketsAttributes?.length &&
          ticketTotalAmount === 0 &&
          !donationAmount &&
          actionPage.event?.requireDonationForFreeTickets ? (
            <Label className="mt-2 text-red-400">
              A general donation is required with the selection of only free tickets.
            </Label>
          ) : null}
        </>
      ) : null}
      {restrictedStateSelected && totalAmount !== 0 ? (
        <div className="mt-3 flex overflow-hidden rounded-lg border border-red-500 bg-neutral-0">
          <div className="flex items-center justify-center bg-red-500 p-4">
            <ExclamationCircleIcon className="h-6 w-6 text-neutral-0" />
          </div>
          <div className="p-4">
            Due to state fundraising regulations, we cannot accept donations from {region}
          </div>
        </div>
      ) : null}
    </>
  );
};

